        }
    }

    return answer;
}

function computeComponents(n: number, edges: number[][], t: number): number {
    const parent = Array(n).fill(0).map((_, i) => i);
    const rank = Array(n).fill(0);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) return false;
        if (rank[rootU] > rank[rootV]) {
            parent[rootV] = rootU;
        } else {
            parent[rootU] = rootV;
            if (rank[rootU] === rank[rootV]) {
                rank[rootV] += 1;
            }
        }
        return true;
    }

    let components = n;
    for (const [u, v, time] of edges) {
        if (time > t) {
            if (union(u, v)) {
                components--;
            }
        }
    }
    return components;
}
